"use strict";(globalThis.webpackChunkship_it_book=globalThis.webpackChunkship_it_book||[]).push([[218],{9422(e,t,n){n.r(t),n.d(t,{assets:()=>l,contentTitle:()=>a,default:()=>u,frontMatter:()=>r,metadata:()=>o,toc:()=>d});const o=JSON.parse('{"id":"part-2-find-the-problem/chapter-2-1-finding-your-identity","title":"Chapter 2.1 \u2014 Finding Your Identity as a Builder","description":"Who you are determines what you build.","source":"@site/docs/part-2-find-the-problem/chapter-2-1-finding-your-identity.mdx","sourceDirName":"part-2-find-the-problem","slug":"/part-2-find-the-problem/chapter-2-1-finding-your-identity","permalink":"/ship-it-book/part-2-find-the-problem/chapter-2-1-finding-your-identity","draft":false,"unlisted":false,"tags":[],"version":"current","frontMatter":{"title":"Chapter 2.1 \u2014 Finding Your Identity as a Builder","description":"Who you are determines what you build.","sidebar_label":"2.1 \u2014 Finding Your Identity"},"sidebar":"book","previous":{"title":"Part 2 \u2014 Find and Validate the Problem","permalink":"/ship-it-book/part-2-find-the-problem/"},"next":{"title":"2.2 \u2014 Reading Markets Without an MBA","permalink":"/ship-it-book/part-2-find-the-problem/chapter-2-2-reading-markets"}}');var i=n(4848),s=n(8453);const r={title:"Chapter 2.1 \u2014 Finding Your Identity as a Builder",description:"Who you are determines what you build.",sidebar_label:"2.1 \u2014 Finding Your Identity"},a="Finding Your Identity as a Builder",l={},d=[{value:"The Identity Question",id:"the-identity-question",level:2},{value:"The Ikigai-Like Framework for Builder Identity",id:"the-ikigai-like-framework-for-builder-identity",level:2},{value:"Real Examples of Builders Who Found Their Niche",id:"real-examples-of-builders-who-found-their-niche",level:2},{value:"How Your Tech Stack Preferences Reveal Your Builder Type",id:"how-your-tech-stack-preferences-reveal-your-builder-type",level:2},{value:"The Self-Assessment Quiz",id:"the-self-assessment-quiz",level:2},{value:"The Taste Gap Problem",id:"the-taste-gap-problem",level:2},{value:"Your Experiences Shape Your Vision",id:"your-experiences-shape-your-vision",level:2},{value:"The Portfolio Identity",id:"the-portfolio-identity",level:2},{value:"The Imposter Trap",id:"the-imposter-trap",level:2},{value:"The Hard Truth",id:"the-hard-truth",level:2},{value:"Your Turn",id:"your-turn",level:2},{value:"What You Learned",id:"what-you-learned",level:2}];function h(e){const t={h1:"h1",h2:"h2",header:"header",li:"li",ol:"ol",p:"p",strong:"strong",ul:"ul",...(0,s.R)(),...e.components};return(0,i.jsxs)(i.Fragment,{children:[(0,i.jsx)(t.header,{children:(0,i.jsx)(t.h1,{id:"finding-your-identity-as-a-builder",children:"Finding Your Identity as a Builder"})}),"\n",(0,i.jsx)(t.p,{children:"Before you can build something people want, you need to know who you are as a builder. Not your job title. Not your tech stack. Your identity."}),"\n",(0,i.jsx)(t.p,{children:"I spent three years trying to build the wrong products because I was trying to be someone I'm not. I built B2B SaaS tools when I'm a consumer-oriented developer. I built for enterprise when I understand individuals. I chased markets that bored me because they seemed profitable."}),"\n",(0,i.jsx)(t.p,{children:"Every product failed. Not because the code was bad. Because I was building as a character I made up, not as myself."}),"\n",(0,i.jsx)(t.h2,{id:"the-identity-question",children:"The Identity Question"}),"\n",(0,i.jsx)(t.p,{children:"Ask yourself: what kind of builder are you?"}),"\n",(0,i.jsxs)(t.ul,{children:["\n",(0,i.jsx)(t.li,{children:"Do you love infrastructure? Do you get excited about databases, deployments, and dev tools?"}),"\n",(0,i.jsx)(t.li,{children:"Do you love user experience? Do you obsess over pixels, interactions, and delight?"}),"\n",(0,i.jsx)(t.li,{children:"Do you love systems? Do you think in workflows, automations, and efficiency?"}),"\n",(0,i.jsx)(t.li,{children:"Do you love teaching? Do you enjoy explaining, documenting, and showing others how?"}),"\n"]}),"\n",(0,i.jsx)(t.p,{children:"None of these is better than the others. But they lead to completely different products. Infra people build databases. UX people build design tools. Systems people build automation. Teachers build courses and guides."}),"\n",(0,i.jsx)(t.p,{children:"The problem comes when an infra person tries to build a consumer app, or a UX person tries to build a deployment platform. It's not impossible, but it's fighting your nature."}),"\n",(0,i.jsx)(t.h2,{id:"the-ikigai-like-framework-for-builder-identity",children:"The Ikigai-Like Framework for Builder Identity"}),"\n",(0,i.jsx)(t.p,{children:"There's a famous Japanese concept called ikigai \u2014 the intersection of what you love, what you're good at, what the world needs, and what you can be paid for. As a builder, a similar framework applies."}),"\n",(0,i.jsx)(t.p,{children:"Your builder identity lives at the intersection of four circles:"}),"\n",(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.strong,{children:"What frustrates you."}),' The bugs, the friction, the "why does nobody fix this?" moments you encounter in your daily work. These are not random annoyances. They\'re signals pointing to problems only you can see because of your specific context.']}),"\n",(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.strong,{children:"What you're skilled at."})," The things you can build faster and better than most. Maybe it's backend architecture. Maybe it's polished frontends. Maybe it's database modeling or API design or developer tooling."]}),"\n",(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.strong,{children:"What users will pay for."})," Not what's theoretically monetizable. What real people actually open their wallets for. This circle shifts based on the market, which is why it's the one you can't learn from introspection alone."]}),"\n",(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.strong,{children:"What sustains you."})," The kind of work you can do for years without burning out. Some builders thrive on constant novelty. Others prefer deep focus on a single product for a decade. Know which one you are before you commit."]}),"\n",(0,i.jsx)(t.p,{children:"The magic happens in the overlap. DHH (David Heinemeier Hansson) found his overlap when he combined his frustration with existing project management tools, his skill at building opinionated software, the market demand for simpler team tools, and a sustainable solo-founder lifestyle. That became Basecamp. The result: a 20-year company that has never taken venture capital and serves millions of users worldwide."}),"\n",(0,i.jsx)(t.p,{children:"Pieter Levels found a different overlap. He was frustrated by the complexity of building and launching startups. He was skilled at rapid prototyping in PHP and JavaScript. The market was hungry for indie-made tools that solved real problems. And he could sustain himself with a nomadic lifestyle on a few thousand dollars a month. That intersection produced Nomad List, Remote OK, and a dozen other profitable products built by one person."}),"\n",(0,i.jsx)(t.p,{children:"Your intersection will look different. That's the point."}),"\n",(0,i.jsx)(t.h2,{id:"real-examples-of-builders-who-found-their-niche",children:"Real Examples of Builders Who Found Their Niche"}),"\n",(0,i.jsx)(t.p,{children:"Let's look at developers who leaned into their identity and won."}),"\n",(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.strong,{children:"DHH"})," (Ruby on Rails, Basecamp, HEY). DHH is the archetype of the opinionated builder. He doesn't ask what the market wants. He builds what he believes is right and trusts that others share his taste. This works because his identity is rooted in strong convictions about software design. He's not trying to please everyone. He's trying to make software that he himself would love."]}),"\n",(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.strong,{children:"Pieter Levels"}),' builds what he calls "tiny startups" \u2014 small, focused products that solve one problem well. His identity is the speed-shipper. He launches in days, not months. He optimizes for iteration over perfection. This identity came from his constraints: he needed income that supported a digital nomad lifestyle, which meant he couldn\'t work on a single product for years.']}),"\n",(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.strong,{children:"Mandy Michael"})," transitioned from designer to frontend developer to creator of generative art courses. Her identity shifted as she explored, but the throughline was always visual communication. She found her niche at the intersection of code and art, creating educational content that taught developers how to think visually."]}),"\n",(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.strong,{children:"Sahil Lavingia"})," (Gumroad) started as a designer at Pinterest, then built Gumroad as a solo founder. His identity as a designer-developer hybrid meant Gumroad had exceptional UX from day one. When the company struggled and he had to lay off his team, he returned to his identity as a solo builder and rebuilt the product himself."]}),"\n",(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.strong,{children:"Tania Rascia"})," built a career by teaching developers how to use modern JavaScript. Her identity as a teacher shaped everything she created: tutorials, open-source projects, and eventually paid courses. She didn't just have technical skills. She had the ability to explain complex topics simply, and she built her entire career around that identity."]}),"\n",(0,i.jsx)(t.p,{children:'The common thread: none of them asked "what product should I build?" first. They asked "who am I as a builder?" and let the products emerge from that answer.'}),"\n",(0,i.jsx)(t.h2,{id:"how-your-tech-stack-preferences-reveal-your-builder-type",children:"How Your Tech Stack Preferences Reveal Your Builder Type"}),"\n",(0,i.jsx)(t.p,{children:"The tools you're drawn to aren't random. They reflect your builder psychology."}),"\n",(0,i.jsxs)(t.p,{children:["Developers who love ",(0,i.jsx)(t.strong,{children:"Elixir"})," or ",(0,i.jsx)(t.strong,{children:"Go"})," tend to be systems thinkers. They care about concurrency, reliability, and architecture. They're drawn to problems that require careful design and predictable performance. These builders often end up creating infrastructure tools, backend platforms, and developer tools."]}),"\n",(0,i.jsxs)(t.p,{children:["Developers who love ",(0,i.jsx)(t.strong,{children:"React"})," or ",(0,i.jsx)(t.strong,{children:"Svelte"})," tend to be experience-focused. They care about how things look and feel. They obsess over component design, state management, and user delight. These builders naturally gravitate toward consumer apps, design tools, and products where UX is the differentiator."]}),"\n",(0,i.jsxs)(t.p,{children:["Developers who love ",(0,i.jsx)(t.strong,{children:"PHP"})," or ",(0,i.jsx)(t.strong,{children:"Ruby"})," tend to be pragmatists. They care about shipping. They want the shortest path from idea to working product. These are the solo founders, the bootstrappers, the creators of CRUD apps that generate revenue. They don't care about elegance. They care about results."]}),"\n",(0,i.jsxs)(t.p,{children:["Developers who love ",(0,i.jsx)(t.strong,{children:"Python"})," or ",(0,i.jsx)(t.strong,{children:"R"})," tend to be data-driven. They think in datasets, algorithms, and outputs. They're comfortable with ambiguity and experimentation. These builders create analytics tools, AI products, and data infrastructure."]}),"\n",(0,i.jsxs)(t.p,{children:["Developers who love ",(0,i.jsx)(t.strong,{children:"CSS"})," and ",(0,i.jsx)(t.strong,{children:"design systems"})," tend to be detail-oriented visual thinkers. They notice misalignments, color inconsistencies, and motion that feels wrong. These are the builders who create design tools, no-code platforms, and creative software."]}),"\n",(0,i.jsx)(t.p,{children:"None of these is right or wrong. But if you're a PHP pragmatist trying to build the next Figma, you're going to struggle. Not because you can't learn JavaScript. Because your instincts will pull you toward practicality when the product demands obsession with pixels."}),"\n",(0,i.jsx)(t.p,{children:"The opposite is also true. If you're a pixel-obsessed React developer trying to build the next Stripe, you'll spend six months on the landing page while competitors ship the actual product."}),"\n",(0,i.jsx)(t.p,{children:"Match your stack instincts to the problem domain. Your natural preferences are telling you something about what you should build."}),"\n",(0,i.jsx)(t.h2,{id:"the-self-assessment-quiz",children:"The Self-Assessment Quiz"}),"\n",(0,i.jsx)(t.p,{children:"Answer these questions honestly. Don't answer who you want to be. Answer who you actually are."}),"\n",(0,i.jsx)(t.p,{children:(0,i.jsx)(t.strong,{children:"Section 1: Your Frustrations"})}),"\n",(0,i.jsxs)(t.ol,{children:["\n",(0,i.jsxs)(t.li,{children:["\n",(0,i.jsx)(t.p,{children:"When you use bad software, what bothers you most?\na) The UI is ugly and confusing\nb) The performance is slow and unreliable\nc) The workflow doesn't make sense\nd) The documentation is terrible"}),"\n"]}),"\n",(0,i.jsxs)(t.li,{children:["\n",(0,i.jsx)(t.p,{children:"When you browse GitHub, what projects catch your eye?\na) Beautiful dashboards and design systems\nb) Database engines and compilers\nc) Automation tools and workflow engines\nd) Tutorials and learning resources"}),"\n"]}),"\n",(0,i.jsxs)(t.li,{children:["\n",(0,i.jsx)(t.p,{children:"If you had a free weekend to build anything, what would you build?\na) A beautiful personal website or portfolio\nb) A CLI tool or developer utility\nc) A habit tracker with automations\nd) A guide or course on something you know"}),"\n"]}),"\n"]}),"\n",(0,i.jsx)(t.p,{children:(0,i.jsx)(t.strong,{children:"Section 2: Your Skills"})}),"\n",(0,i.jsxs)(t.ol,{start:"4",children:["\n",(0,i.jsxs)(t.li,{children:["\n",(0,i.jsx)(t.p,{children:"What do your colleagues come to you for?\na) Design feedback and UX advice\nb) Performance optimization and architecture\nc) Process improvements and automation\nd) Explanations and teaching"}),"\n"]}),"\n",(0,i.jsxs)(t.li,{children:["\n",(0,i.jsx)(t.p,{children:"What part of building a product do you enjoy most?\na) The visual design and interaction details\nb) The data model and system architecture\nc) The workflow and business logic\nd) The documentation and onboarding"}),"\n"]}),"\n"]}),"\n",(0,i.jsx)(t.p,{children:(0,i.jsx)(t.strong,{children:"Section 3: Your Constraints"})}),"\n",(0,i.jsxs)(t.ol,{start:"6",children:["\n",(0,i.jsxs)(t.li,{children:["\n",(0,i.jsx)(t.p,{children:"How much time can you realistically dedicate per week?\na) 5-10 hours (side project)\nb) 10-20 hours (serious side project)\nc) 20-40 hours (part-time business)\nd) 40+ hours (full-time commitment)"}),"\n"]}),"\n",(0,i.jsxs)(t.li,{children:["\n",(0,i.jsx)(t.p,{children:"What's your risk tolerance?\na) I need revenue within a month\nb) I can go 3-6 months without revenue\nc) I can go a year without revenue\nd) I have funding and can go multiple years"}),"\n"]}),"\n"]}),"\n",(0,i.jsx)(t.p,{children:(0,i.jsx)(t.strong,{children:"Scoring:"})}),"\n",(0,i.jsxs)(t.p,{children:["Mostly As: You're a ",(0,i.jsx)(t.strong,{children:"craft builder"}),". Your advantage is taste and polish. Build consumer products where design matters. Don't try to compete on features. Compete on how your product makes people feel."]}),"\n",(0,i.jsxs)(t.p,{children:["Mostly Bs: You're a ",(0,i.jsx)(t.strong,{children:"systems builder"}),". Your advantage is reliability and performance. Build tools for developers, infrastructure products, and backend platforms. Don't try to compete on marketing. Compete on technical excellence."]}),"\n",(0,i.jsxs)(t.p,{children:["Mostly Cs: You're a ",(0,i.jsx)(t.strong,{children:"workflow builder"}),". Your advantage is efficiency and simplicity. Build automation tools, productivity apps, and business software. Don't try to compete on flash. Compete on getting things done."]}),"\n",(0,i.jsxs)(t.p,{children:["Mostly Ds: You're a ",(0,i.jsx)(t.strong,{children:"teacher builder"}),". Your advantage is clarity and communication. Build courses, documentation tools, and educational platforms. Don't try to compete on features. Compete on how well you transfer understanding."]}),"\n",(0,i.jsx)(t.p,{children:"Mixed scores mean you're a hybrid. That's fine. Use this as a starting point, not a cage."}),"\n",(0,i.jsx)(t.h2,{id:"the-taste-gap-problem",children:"The Taste Gap Problem"}),"\n",(0,i.jsx)(t.p,{children:"There's a phenomenon every builder encounters. You have great taste. You can recognize good design, good code, good products. But your early creations don't match your standards. You build something and it feels... off. Not good enough. Embarrassing."}),"\n",(0,i.jsx)(t.p,{children:'This is the taste gap. Ira Glass described it perfectly: "Your taste is why your work disappoints you. A lot of people never get past this phase. They quit."'}),"\n",(0,i.jsx)(t.p,{children:"The taste gap kills more builders than bad markets or technical challenges."}),"\n",(0,i.jsx)(t.p,{children:"How do you bridge the taste gap? Not by raising your skills. By lowering your expectations for early work. Your first product should embarrass you. Your second should be slightly less embarrassing. By your tenth, the gap starts to close."}),"\n",(0,i.jsx)(t.p,{children:"The mistake is thinking you can skip ahead. You can't build product #10 without building products #1 through #9 first. Each one teaches you something that no book or course can teach."}),"\n",(0,i.jsx)(t.p,{children:"Nick Disabato calls this \"taste-driven development.\" Your taste tells you what good looks like. Your skills haven't caught up yet. That's okay. The gap closes one shipped product at a time."}),"\n",(0,i.jsx)(t.p,{children:"Here's the practical approach: set a quality floor, not a quality ceiling. Decide what minimum quality you need to ship (it works, it solves the problem, it doesn't crash). Then ship it. Don't wait until it meets your taste standards. Your taste standards evolve as you build."}),"\n",(0,i.jsx)(t.p,{children:'Paul Graham wrote about "schlep blindness" \u2014 the tendency to ignore the grungy work that a good product requires. The taste gap is a form of schlep blindness. You see the gap between your vision and your output, and you conclude the vision is wrong. It\'s not. The gap is normal. Keep building.'}),"\n",(0,i.jsx)(t.h2,{id:"your-experiences-shape-your-vision",children:"Your Experiences Shape Your Vision"}),"\n",(0,i.jsx)(t.p,{children:"You bring unique context to every problem. Your background as a self-taught developer from a non-Western country isn't a disadvantage. It's your lens."}),"\n",(0,i.jsx)(t.p,{children:"You understand what it's like to learn without resources. You know the frustration of finding tutorials made for people with CS degrees. You know the pain of building with a slow internet connection and an old laptop."}),"\n",(0,i.jsx)(t.p,{children:"These experiences let you see problems that others miss. The best products come from personal frustration. Your frustration is your advantage."}),"\n",(0,i.jsx)(t.p,{children:"Stripe was founded by two Irish brothers who were frustrated with how hard it was to accept payments online. They had experienced the problem firsthand when building their own apps. That personal frustration drove them to build something that processing millions of dollars in payments daily."}),"\n",(0,i.jsx)(t.p,{children:"GitHub was built by developers who were frustrated with the existing tools for sharing code. They built what they needed themselves. That personal context \u2014 being developers who hated SourceForge \u2014 was the insight that produced a billion-dollar company."}),"\n",(0,i.jsx)(t.p,{children:"Your background isn't something to overcome. It's something to use."}),"\n",(0,i.jsx)(t.h2,{id:"the-portfolio-identity",children:"The Portfolio Identity"}),"\n",(0,i.jsx)(t.p,{children:"Don't decide your identity by thinking. Decide by shipping."}),"\n",(0,i.jsx)(t.p,{children:"Build small things. See what feels natural. See what users respond to. See what keeps you up at night because you can't stop thinking about it."}),"\n",(0,i.jsx)(t.p,{children:"Your identity as a builder is not something you discover in meditation. It's something you uncover through action. Every project teaches you something about what you enjoy and what you're good at. Over time, a pattern emerges."}),"\n",(0,i.jsx)(t.p,{children:'Keep a "makers log." After each project, write down:'}),"\n",(0,i.jsxs)(t.ul,{children:["\n",(0,i.jsx)(t.li,{children:"What felt easy and natural"}),"\n",(0,i.jsx)(t.li,{children:"What felt like a struggle"}),"\n",(0,i.jsx)(t.li,{children:"What users appreciated most"}),"\n",(0,i.jsx)(t.li,{children:"What you'd do differently"}),"\n"]}),"\n",(0,i.jsx)(t.p,{children:"Review this log after three projects. You'll see your identity in the patterns."}),"\n",(0,i.jsx)(t.h2,{id:"the-imposter-trap",children:"The Imposter Trap"}),"\n",(0,i.jsx)(t.p,{children:"You'll be tempted to build what you think a \"real founder\" would build. You'll see YC companies raising millions for enterprise SaaS and think you need to do the same."}),"\n",(0,i.jsx)(t.p,{children:"Stop. You are not a YC founder (yet). You're you. Your constraints are different. Your advantages are different. Build something that fits your life."}),"\n",(0,i.jsx)(t.p,{children:"If you have a full-time job, build something that doesn't need 24/7 uptime. If you have limited social media following, build something that spreads through quality, not network effects. If you're a solo developer, build something one person can maintain."}),"\n",(0,i.jsx)(t.p,{children:"The most dangerous identity is the one you invent because you think it's expected of you. The most powerful identity is the one that's already true."}),"\n",(0,i.jsx)(t.h2,{id:"the-hard-truth",children:"The Hard Truth"}),"\n",(0,i.jsx)(t.p,{children:"Nobody cares what kind of builder you think you are. The market only cares about the value you create. Your identity is just a tool for finding your edge. It's not a badge to wear."}),"\n",(0,i.jsx)(t.p,{children:"But ignoring your identity is like using a screwdriver to hammer a nail. You can do it. It just takes ten times longer and produces worse results."}),"\n",(0,i.jsx)(t.p,{children:"Your identity is a starting point, not a straitjacket. Use it to find your direction. Then ship, learn, and adjust."}),"\n",(0,i.jsx)(t.h2,{id:"your-turn",children:"Your Turn"}),"\n",(0,i.jsx)(t.p,{children:"Take the self-assessment quiz above. Write down your score and what it suggests."}),"\n",(0,i.jsx)(t.p,{children:"Then answer these three questions:"}),"\n",(0,i.jsxs)(t.ol,{children:["\n",(0,i.jsx)(t.li,{children:"What kind of problems do I naturally notice?"}),"\n",(0,i.jsx)(t.li,{children:"What kind of building makes me lose track of time?"}),"\n",(0,i.jsx)(t.li,{children:"What is one constraint in my life that I should build around instead of fighting?"}),"\n"]}),"\n",(0,i.jsx)(t.p,{children:"Finally, identify one project you can ship in the next two weeks that aligns with your builder identity. It doesn't have to be a business. It can be a tool, a tutorial, a template, or a small app. The goal is action, not perfection."}),"\n",(0,i.jsx)(t.p,{children:"Spend 20 minutes on this. Don't skip it."}),"\n",(0,i.jsx)(t.h2,{id:"what-you-learned",children:"What You Learned"}),"\n",(0,i.jsxs)(t.ul,{children:["\n",(0,i.jsx)(t.li,{children:"Your builder identity shapes what products you should build"}),"\n",(0,i.jsx)(t.li,{children:"The ikigai-like framework helps you find your intersection: frustration, skill, market, and sustainability"}),"\n",(0,i.jsx)(t.li,{children:"Real builders like DHH, Pieter Levels, and Tania Rascia succeeded by leaning into their identity"}),"\n",(0,i.jsx)(t.li,{children:"Your tech stack preferences reveal your builder psychology"}),"\n",(0,i.jsx)(t.li,{children:"The taste gap is normal \u2014 bridge it by shipping early and often"}),"\n",(0,i.jsx)(t.li,{children:"Personal frustrations are product opportunities"}),"\n",(0,i.jsx)(t.li,{children:"Your background is your advantage, not your limitation"}),"\n",(0,i.jsx)(t.li,{children:"Identity emerges from action, not introspection"}),"\n",(0,i.jsx)(t.li,{children:"Build according to your constraints, not someone else's situation"}),"\n"]})]})}function u(e={}){const{wrapper:t}={...(0,s.R)(),...e.components};return t?(0,i.jsx)(t,{...e,children:(0,i.jsx)(h,{...e})}):h(e)}},8453(e,t,n){n.d(t,{R:()=>r,x:()=>a});var o=n(6540);const i={},s=o.createContext(i);function r(e){const t=o.useContext(s);return o.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function a(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:r(e.components),o.createElement(s.Provider,{value:t},e.children)}}}]);